63	async function createMusicCard(args: MusicCardArgs): Promise<string> {
64	  const cardsDir = fromRoot("vault", "studio", "references", "shared", "music-cards");
65	  const audioDir = join(cardsDir, "audio");
66	  const cardType = (args.type || "background-mix") as CardType;
67	  let startSec = args.start ?? 300;
68	  let duration = args.duration ?? 300;
69	
70	  const out: string[] = [];
71	
72	  // 1. Fetch metadata
73	  out.push("Fetching metadata...");
74	  const meta = fetchMetadata(args.url);
75	  if (args.title) meta.title = args.title;
76	  out.push(`  Title: ${meta.title}`);
77	  out.push(`  Channel: ${meta.channel}`);
78	  out.push(`  Duration: ${Math.floor(meta.duration / 60)}m${meta.duration % 60}s`);
79	
80	  // 2. Derive slug
81	  let slug = args.slug || "";
82	  if (!slug) {
83	    slug = meta.title
84	      .toLowerCase()
85	      .replace(/[^\w\s-]/g, "")
86	      .replace(/\s+/g, "-")
87	      .replace(/-+/g, "-")
88	      .replace(/^-|-$/g, "");
89	    if (slug.length > 32) {
90	      slug = slug.slice(0, 32).replace(/-[^-]*$/, "");
91	    }
92	  }
93	
94	  const baseSlug = slug; // stable key for download caching
95	  const datePrefix = dayjs().format("YYYY-MM-DD-HHmmss");
96	  const cardSlug = `${datePrefix}-${slug}`;
97	  const audioSlug = `${datePrefix}-${slug}`;
98	
99	  if (existsSync(join(cardsDir, `${cardSlug}.md`))) {
100	    throw new Error(`Card already exists: ${cardSlug}.md — use --slug to specify a different name.`);
101	  }
102	
103	  out.push(`  Card slug: ${cardSlug}`);
104	  out.push(`  Audio slug: ${audioSlug}`);
105	
106	  // 3. Clamp sample window
107	  if (startSec + duration > meta.duration) {
108	    if (meta.duration <= duration) {
109	      startSec = 0;
110	      duration = meta.duration;
111	      out.push(`  Source shorter than sample — extracting full audio (${formatDuration(duration)})`);
112	    } else {
113	      startSec = Math.max(0, meta.duration - duration);
114	      out.push(`  Adjusted start to ${startSec}s to fit within source`);
115	    }
116	  }
