121	  out.push(`  Audio: ${audioSlug}.mp3 (${extract.fileSizeMB}MB, ${formatTime(extract.actualDuration)})`);
122	
123	  // 5. Audio analysis
124	  let audioAnalysis = null;
125	  if (!args.skipAnalyze) {
126	    out.push("Analyzing audio...");
127	    audioAnalysis = analyzeAudio(extract.audioFile);
128	    if (audioAnalysis) {
129	      out.push(`  BPM: ${audioAnalysis.bpm} | Key: ${audioAnalysis.key.label} | Energy: ${audioAnalysis.energy.level} | Brightness: ${audioAnalysis.spectral.brightness}`);
130	    } else {
131	      out.push("  Audio analysis unavailable — falling back to metadata-only profile");
132	    }
133	  }
134	
135	  // 6. Build profile + card
136	  out.push("Building profile from metadata...");
137	  const profile = analyzeFromMetadata(meta);
138	  const sampleLabel = `${formatTime(startSec)}–${formatTime(startSec + extract.actualDuration)}`;
139	  const durationLabel = formatDuration(extract.actualDuration);
140	  const today = dayjs().format("YYYY-MM-DD");
141	
142	  const cardContent = buildCard({
143	    meta, profile, audioAnalysis, audioSlug, cardType,
144	    sampleLabel, durationLabel, sourceUrl: args.url, today,
145	  });
146	
147	  const cardFile = join(cardsDir, `${cardSlug}.md`);
148	  writeFileSync(cardFile, cardContent, "utf-8");
149	  out.push(`  Card: ${cardSlug}.md`);
150	
151	  // 7. Gemini refinement
152	  if (!args.skipAnalyze) {
153	    out.push("Refining with Gemini...");
154	    const refined = await refineWithGemini({ meta, cardType, cardContent, audioAnalysis, genre: args.genre, mood: args.mood });
155	    if (refined) {
