157	      out.push("  Gemini refinement applied");
158	      if (refined.usage) out.push(`  Gemini: ${refined.usage}`);
159	    } else {
160	      out.push("  Gemini refinement skipped — keeping metadata-based version");
161	    }
162	  }
163	
164	  // 8. Summary
165	  const ytTags = meta.tags.slice(0, 10).map(t => t.toLowerCase().replace(/\s+/g, "-"));
166	  out.push("");
167	  out.push("=== MUSIC CARD CREATED ===");
168	  out.push(JSON.stringify({
169	    slug: cardSlug, audioSlug, card: cardFile, audio: extract.audioFile,
170	    type: cardType, source: args.url, sample: sampleLabel,
171	    duration: durationLabel, title: meta.title, channel: meta.channel, tags: ytTags,
172	  }, null, 2));
173	  out.push("=== END ===");
174	
175	  return out.join("\n");
176	}
177	
