191	    genre: z.string().optional().describe("User-defined genre hint for Gemini refinement"),
192	    mood: z.string().optional().describe("User-defined mood hint for Gemini refinement"),
193	    skipAnalyze: z.boolean().optional().describe("Skip audio analysis and Gemini refinement"),
