1	/**
2	 * refine.ts — Gemini refinement pass for music cards
3	 *
4	 * Takes the generated card + metadata + audio analysis and asks Gemini
5	 * to improve mood descriptions, groove details, and translations.
6	 */
7	
8	import { generateText } from "../../libs/gemini.js";
9	import type { YtMeta } from "./profiles.js";
10	import type { AudioAnalysis } from "./analyze.js";
11	
12	export interface RefineInput {
13	  meta: YtMeta;
14	  cardType: string;
15	  cardContent: string;
16	  audioAnalysis: AudioAnalysis | null;
17	  genre?: string;
18	  mood?: string;
19	}
20	
21	/**
22	 * Refine a music card via Gemini. Returns the improved card content,
23	 * or null if refinement fails (caller should keep the original).
24	 */
25	export async function refineWithGemini(input: RefineInput): Promise<{ refined: string; usage?: string } | null> {
26	  const { meta, cardType, cardContent, audioAnalysis, genre, mood } = input;
27	
28	  const userContextSection = (genre || mood)
29	    ? `\nUser-provided context (use as strong hints for genre matching and translations):${genre ? `\n  Genre: ${genre}` : ""}${mood ? `\n  Mood: ${mood}` : ""}\n`
30	    : "";
31	
32	  const audioDataSection = audioAnalysis
33	    ? `\nAudio analysis (from librosa — these are measured values, trust them):
34	  BPM: ${audioAnalysis.bpm}
35	  Key: ${audioAnalysis.key.label} (confidence: ${audioAnalysis.key.confidence})
36	  Energy: ${audioAnalysis.energy.level} (RMS: ${audioAnalysis.energy.rms}, dynamics: ${audioAnalysis.energy.dynamics})
37	  Spectral: brightness=${audioAnalysis.spectral.brightness}, width=${audioAnalysis.spectral.width} (centroid: ${audioAnalysis.spectral.centroid}Hz)
38	  Rhythm density: ${audioAnalysis.rhythm.density} (${audioAnalysis.rhythm.onsetsPerSec} onsets/sec)\n`
39	    : "";
40	
41	  const prompt = `You are a music production analyst. Given this music card with values derived from YouTube metadata and audio analysis, refine and improve the analysis based on your knowledge of the genre(s).
42	
43	Title: ${meta.title}
44	Channel: ${meta.channel}
45	Tags: ${meta.tags.join(", ")}
46	Description: ${meta.description}
47	Card type: ${cardType}
48	${userContextSection}${audioDataSection}
49	Current card content:
50	${cardContent}
51	
52	Return ONLY the updated card content (everything between and including the --- frontmatter delimiters). Keep the same structure. The BPM and Key values from audio analysis are measured — keep them accurate (don't replace with ranges). Improve mood descriptions, groove details, palette instruments, and translations based on genre knowledge and the audio data. Make the Suno translation a comma-separated list of style tags. Make the MiniMax translation a natural-language prompt. Do not add new sections. Do not remove any sections. Do not change the Audio embed line.`;
53	
54	  try {
55	    const result = await generateText(prompt, {
56	      model: "gemini-2.5-flash",
57	      timeout: 90_000,
58	      temperature: 0.4,
59	      caller: "musiccard",
60	    });
61	
62	    const fmMatch = result.text.match(/^---\n[\s\S]*?\n---[\s\S]*/m);
63	    if (!fmMatch) return null;
64	
65	    const usage = (result.inputTokens || result.outputTokens)
66	      ? `${result.inputTokens ?? "?"} in / ${result.outputTokens ?? "?"} out tokens`
67	      : undefined;
68	
69	    return { refined: fmMatch[0].trim() + "\n", usage };
70	  } catch {
71	    return null;
72	  }
73	}
