 * Order: file exists → extension → env vars (cheapest-first per spec Note 9).
 * Returns structured error on failure, null on success.
 */
export function validateInputs(filePath: string): { code: number; message: string } | null {
  if (!existsSync(filePath)) {
    return { code: 1, message: `Audio file not found: ${filePath}` };
  }
  const ext = extname(filePath).toLowerCase();
  if (ext !== ".mp3") {
    return { code: 1, message: `Only mp3 files are supported in v1. Got: ${ext || "(no extension)"}` };
  }
  if (!process.env.SUNO_AUTHORIZATION) {
    return {
      code: 1,
      message:
        "SUNO_AUTHORIZATION is not set. Run 'suno-meta --setup-help' for extraction instructions.",
    };
  }
  if (!process.env.SUNO_BROWSER_TOKEN) {
    return {
      code: 1,
      message:
        "SUNO_BROWSER_TOKEN is not set. Run 'suno-meta --setup-help' for extraction instructions.",
    };
  }
  if (!process.env.SUNO_DEVICE_ID) {
    return {
      code: 1,
      message:
        "SUNO_DEVICE_ID is not set. Run 'suno-meta --setup-help' for extraction instructions.",
    };
  }
  return null;
}

// ── Helpers ────────────────────────────────────────────────────────────────────

async function safeSnippet(res: Response): Promise<string> {
  try {
    const text = await res.text();
    return text.slice(0, 120);
  } catch {
    return "(unreadable body)";
  }
}

