// ── Step 1 — Create upload session ────────────────────────────────────────────

interface Step1Response {
  id: string;
  url: string;
  fields: Record<string, string>;
}

export async function step1CreateUploadSession(): Promise<Step1Response> {
  const res = await fetch(`${BASE}/api/uploads/audio/`, {
    method: "POST",
    headers: sunoHeaders({ "content-type": "application/json" }),
    body: JSON.stringify({ extension: "mp3" }),
  });

  if (res.status === 401) {
    throw new SunoError(
      "Suno rejected auth. Token may be expired. Run 'suno-meta --check-token' to verify, or --setup-help to refresh.",
      2
    );
  }
  if (res.status >= 400 && res.status < 500) {
    const snippet = await safeSnippet(res);
    throw new SunoError(
      `Suno API error on upload session creation: ${res.status} ${snippet}`,
      3
    );
  }
  if (res.status >= 500) {
    throw new SunoError(
      `Suno API 5xx on upload session creation: ${res.status}. Retry in a few moments.`,
      4
    );
  }

  const data = await res.json() as { id?: string; url?: string; fields?: Record<string, string> };
  if (!data.id || !data.url || !data.fields) {
    throw new SunoError(
      "Suno returned unexpected response shape at step 1. Expected 'id', 'url', 'fields'.",
      7
    );
  }
  return { id: data.id, url: data.url, fields: data.fields };
}

// ── Step 2 — S3 upload (pre-signed POST, 3x retry w/ exponential backoff) ─────

export async function step2S3Upload(
  s3Url: string,
  fields: Record<string, string>,
  filePath: string
): Promise<void> {
  let lastError = "Unknown S3 error";

  for (let attempt = 0; attempt < S3_MAX_RETRIES; attempt++) {
    if (attempt > 0) {
      await sleep(S3_BACKOFF_MS[attempt - 1]);
    }
    try {
      // Build FormData: step-1 fields in order, THEN file (ordering is load-bearing for SigV4)
      const form = new FormData();
      // Append step-1 fields verbatim — do not reorder, modify casing, or add extras.
      for (const [key, value] of Object.entries(fields)) {
        form.append(key, value);
      }
      // file MUST be appended last — S3 SigV4 pre-signed POST requires this.
      // Bun.file() avoids Windows path encoding issues with multipart.
      const fileBlob = Bun.file(filePath);
      form.append("file", fileBlob, basename(filePath));

      // S3 upload: NO Suno auth headers. Different host — different auth context.
      const res = await fetch(s3Url, { method: "POST", body: form });

      if (res.status === 204 || res.status === 200) return; // success
      const text = await res.text().catch(() => "");
      lastError = `HTTP ${res.status}: ${text.slice(0, 200)}`;
    } catch (err: any) {
      lastError = err?.message ?? String(err);
    }
  }

  throw new SunoError(`S3 upload failed after 3 retries: ${lastError}`, 5);
}

// ── Step 3 — Notify upload complete ───────────────────────────────────────────

export async function step3UploadFinish(uploadId: string, originalFilename: string): Promise<void> {
  const res = await fetch(`${BASE}/api/uploads/audio/${uploadId}/upload-finish/`, {
    method: "POST",
    headers: sunoHeaders({ "content-type": "application/json" }),
    body: JSON.stringify({
      upload_type: "file_upload",
      upload_filename: originalFilename,
    }),
  });
  if (!res.ok) {
    const snippet = await safeSnippet(res);
    throw new SunoError(
      `Unexpected error: step3 upload-finish failed: ${res.status} ${snippet}. If this reproduces, capture HAR and open an issue.`,
      99
    );
  }
}

// ── Step 4 — Poll for analysis completion ─────────────────────────────────────

export async function step4PollForComplete(
  uploadId: string,
  timeoutMs = POLL_TIMEOUT_MS
): Promise<void> {

