/**
 * extract.ts — Download and trim audio from YouTube, or copy a local file.
 *
 * YouTube mode: chains yt-dlp (download) → ffmpeg (trim + convert) → ffprobe (verify).
 * Local file mode: copy as-is, probe duration via ffprobe.
 * Returns the path to the audio file and actual duration.
 */

import { execSync } from "child_process";
import { existsSync, mkdirSync, readdirSync, statSync, copyFileSync } from "fs";
import { join, extname, basename } from "path";
import { resolveBin } from "../../libs/resolve-bin.js";
import { PROJECT_ROOT, fromRoot } from "../../libs/paths.js";
import type { YtMeta } from "./profiles.js";

const CACHE_DIR = fromRoot("out", "musiccard");

// ── Binary resolution ──────────────────────────────────────────────────────

function resolveBinaries() {
  let ytdlp: string, ffmpeg: string, ffprobe: string;

  try { ytdlp = resolveBin("yt-dlp", PROJECT_ROOT); }
  catch { throw new Error("yt-dlp not found. Install: winget install yt-dlp.yt-dlp (or brew install yt-dlp)"); }

  try { ffmpeg = resolveBin("ffmpeg", PROJECT_ROOT); }
  catch { throw new Error("ffmpeg not found. Install: winget install yt-dlp.FFmpeg (or brew install ffmpeg)"); }

  try { ffprobe = resolveBin("ffprobe", PROJECT_ROOT); }
  catch {
    const candidate = ffmpeg.replace(/ffmpeg(\.exe)?$/, "ffprobe$1");
    if (existsSync(candidate)) { ffprobe = candidate; }
    else { throw new Error("ffprobe not found. Install ffmpeg (includes ffprobe)."); }
  }

  return { ytdlp, ffmpeg, ffprobe };
}

// ── Metadata ───────────────────────────────────────────────────────────────

export function fetchMetadata(url: string): YtMeta {
  const { ytdlp } = resolveBinaries();
  const raw = execSync(`"${ytdlp}" --dump-json "${url}"`, {
    encoding: "utf-8",
    timeout: 30_000,
    stdio: ["pipe", "pipe", "pipe"],
  });
  const data = JSON.parse(raw);
  return {
    title: data.title || "Untitled",
    channel: data.channel || data.uploader || "Unknown",
    duration: data.duration || 0,
    tags: data.tags || [],
    description: (data.description || "").slice(0, 500),
