/**
 * extract.ts — Download and trim audio from YouTube, or copy a local file.
 *
 * YouTube mode: chains yt-dlp (download) → ffmpeg (trim + convert) → ffprobe (verify).
 * Local file mode: copy as-is, probe duration via ffprobe.
 * Returns the path to the audio file and actual duration.
 */

import { execSync } from "child_process";
import { existsSync, mkdirSync, readdirSync, statSync, copyFileSync } from "fs";
import { join, extname, basename } from "path";
import { resolveBin } from "../../libs/resolve-bin.js";
import { PROJECT_ROOT, fromRoot } from "../../libs/paths.js";
import type { YtMeta } from "./profiles.js";

const CACHE_DIR = fromRoot("out", "musiccard");

// ── Binary resolution ──────────────────────────────────────────────────────

function resolveBinaries() {
  let ytdlp: string, ffmpeg: string, ffprobe: string;

  try { ytdlp = resolveBin("yt-dlp", PROJECT_ROOT); }
  catch { throw new Error("yt-dlp not found. Install: winget install yt-dlp.yt-dlp (or brew install yt-dlp)"); }

  try { ffmpeg = resolveBin("ffmpeg", PROJECT_ROOT); }
  catch { throw new Error("ffmpeg not found. Install: winget install yt-dlp.FFmpeg (or brew install ffmpeg)"); }

  try { ffprobe = resolveBin("ffprobe", PROJECT_ROOT); }
  catch {
    const candidate = ffmpeg.replace(/ffmpeg(\.exe)?$/, "ffprobe$1");
    if (existsSync(candidate)) { ffprobe = candidate; }
    else { throw new Error("ffprobe not found. Install ffmpeg (includes ffprobe)."); }
  }

  return { ytdlp, ffmpeg, ffprobe };
}

// ── Metadata ───────────────────────────────────────────────────────────────

export function fetchMetadata(url: string): YtMeta {
  const { ytdlp } = resolveBinaries();
  let raw: string;
  try {
    raw = execSync(`"${ytdlp}" --dump-json "${url}"`, {
      encoding: "utf-8",
      timeout: 120_000,
      maxBuffer: 50 * 1024 * 1024,
      stdio: ["pipe", "pipe", "pipe"],
    });
  } catch (err: any) {
    const stderr = err?.stderr?.toString?.() ?? "";
    throw new Error(`[fetchMetadata] yt-dlp failed: ${stderr || err?.message || String(err)}`);
  }
  const data = JSON.parse(raw);
  return {
    title: data.title || "Untitled",
    channel: data.channel || data.uploader || "Unknown",
    duration: data.duration || 0,
    tags: data.tags || [],
    description: (data.description || "").slice(0, 500),
  };
}

// ── Download + Trim ────────────────────────────────────────────────────────

export interface ExtractResult {
  audioFile: string;
  actualDuration: number;
  fileSizeMB: string;
}

export function downloadAndTrim(
  url: string,
  audioDir: string,
  audioSlug: string,
  startSec: number,
  duration: number,
  cacheSlug?: string,
): ExtractResult {
  const { ytdlp, ffmpeg, ffprobe } = resolveBinaries();

  mkdirSync(audioDir, { recursive: true });

  const audioFile = join(audioDir, `${audioSlug}.mp3`);

  // Step 1: Download best audio (with cache support)
  // Cache full downloads in out/musiccard/ — stable slug (no timestamp) for reuse
  mkdirSync(CACHE_DIR, { recursive: true });
  const stableSlug = cacheSlug || audioSlug;
  const cachedFiles = readdirSync(CACHE_DIR)
    .filter((f: string) => f.startsWith(`${stableSlug}-full.`) && !f.endsWith(".part"))
    .map((f: string) => join(CACHE_DIR, f));

  let sourceFile: string;

  if (cachedFiles.length > 0) {
    // Cache hit — skip download
    sourceFile = cachedFiles[0];
  } else {
    // Cache miss — download full audio to out/musiccard/
    const tempRaw = join(CACHE_DIR, `${stableSlug}-full.%(ext)s`);
    execSync(
      `"${ytdlp}" -f "bestaudio" -o "${tempRaw}" "${url}"`,
      { timeout: 120_000, stdio: ["pipe", "pipe", "pipe"] },
    );

    const downloaded = readdirSync(CACHE_DIR)
      .filter((f: string) => f.startsWith(`${stableSlug}-full.`) && !f.endsWith(".part"))
      .map((f: string) => join(CACHE_DIR, f));

    if (downloaded.length === 0) {
      throw new Error("Download produced no output file");
    }

    sourceFile = downloaded[0];
  }

  // Step 2: Trim + convert to MP3
  execSync(
    `"${ffmpeg}" -y -ss ${startSec} -t ${duration} -i "${sourceFile}" -vn -acodec libmp3lame -ab 192k "${audioFile}"`,
    { timeout: 60_000, stdio: ["pipe", "pipe", "pipe"] },
  );

  // Step 3: Verify with ffprobe
  let actualDuration = 0;
  try {
    const probe = execSync(
      `"${ffprobe}" -v quiet -show_entries format=duration -of csv=p=0 "${audioFile}"`,
      { encoding: "utf-8", timeout: 10_000 },
    );
    actualDuration = Math.round(parseFloat(probe.trim()));
  } catch {}

  const fileSizeMB = (statSync(audioFile).size / 1024 / 1024).toFixed(1);

  return { audioFile, actualDuration: actualDuration || duration, fileSizeMB };
}

// ── Local file helpers ─────────────────────────────────────────────────────

/**
 * Probe the duration of a local audio file using ffprobe.
 * Returns duration in seconds (float).
 * Throws a clear error if ffprobe is not on PATH or the file is unreadable.
 */
export function probeDurationSeconds(filePath: string): number {
  let ffprobe: string;
  try {
    ffprobe = resolveBin("ffprobe", PROJECT_ROOT);
  } catch {
    // Also try sibling of ffmpeg
    try {
      const ff = resolveBin("ffmpeg", PROJECT_ROOT);
      const candidate = ff.replace(/ffmpeg(\.exe)?$/, "ffprobe$1");
      if (existsSync(candidate)) {
        ffprobe = candidate;
      } else {
        throw new Error("ffprobe not found. Install ffmpeg to enable local file music cards.");
      }
    } catch {
      throw new Error("ffprobe not found. Install ffmpeg to enable local file music cards.");
    }
  }

  let stdout: string;
  try {
    stdout = execSync(
      `"${ffprobe}" -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "${filePath}"`,
      { encoding: "utf-8", timeout: 10_000, stdio: ["pipe", "pipe", "pipe"] },
    );
  } catch (err: any) {
    const stderr = err?.stderr?.toString?.() ?? "";
    throw new Error(`ffprobe failed on "${filePath}": ${stderr || err?.message || String(err)}`);
  }

  const secs = parseFloat(stdout.trim());
  if (isNaN(secs)) {
    throw new Error(`ffprobe returned non-numeric duration for "${filePath}": "${stdout.trim()}"`);
  }
  return secs;
}

/**
 * Copy a local audio file into the music-cards audio directory and probe its duration.
 * Mirrors downloadAndTrim()'s return shape — callers can interchange the two.
 *
 * Accepted formats: .mp3 and .wav only. Other extensions throw before any copy.
 */
export function extractLocalFile(
  srcPath: string,
  audioDir: string,
  audioSlug: string,
): ExtractResult {
  if (!existsSync(srcPath)) {
    throw new Error(`Local file not found: ${srcPath}`);
  }

  const ext = extname(srcPath).toLowerCase();
  if (![".mp3", ".wav"].includes(ext)) {
    throw new Error(`Unsupported local file format: ${ext}. Expected .mp3 or .wav.`);
  }

  mkdirSync(audioDir, { recursive: true });

  const destFile = join(audioDir, `${audioSlug}${ext}`);

  // Copy without re-encoding — format-agnostic, no transcoding
  copyFileSync(srcPath, destFile);

  const actualDurationRaw = probeDurationSeconds(destFile);
  const actualDuration = Math.round(actualDurationRaw);
  const fileSizeMB = (statSync(destFile).size / 1024 / 1024).toFixed(1);

  return { audioFile: destFile, actualDuration, fileSizeMB };
}

